#include <unordered_map>
#include <climits>
#include <tuple>

using namespace std;

struct State {
    long long cost;
    int i;
    int j;
    int k;

    bool operator<(const State& other) const {
        return cost > other.cost;
    }
};

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    if (m == 0) return -1;
    int n = grid[0].size();

    priority_queue<State> heap;
    heap.push({0, 0, 0, static_cast<int>(k)});

