    while (!heap.empty()) {
        State current = heap.top();
        heap.pop();
        long long current_cost = current.cost;
        int i = current.i;
        int j = current.j;
        int remaining_k = current.k;

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (visited[i][j][remaining_k] < current_cost) {
            continue;
        }

        // Normal moves
        for (auto& dir : directions) {
            int ni = i + dir.first;
            int nj = j + dir.second;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long new_cost = current_cost + grid[ni][nj];
                if (visited[ni][nj].find(remaining_k) == visited[ni][nj].end() || new_cost < visited[ni][nj][remaining_k]) {
                    visited[ni][nj][remaining_k] = new_cost;
                    heap.push({new_cost, ni, nj, remaining_k});
                }
            }
        }

        // Teleport moves
        if (remaining_k > 0) {
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if ((x != i || y != j) && grid[x][y] <= grid[i][j]) {
                        if (visited[x][y].find(remaining_k - 1) == visited[x][y].end() || current_cost < visited[x][y][remaining_k - 1]) {
                            visited[x][y][remaining_k - 1] = current_cost;
                            heap.push({current_cost, x, y, remaining_k - 1});
                        }
                    }
                }
            }
        }
    }

    return -1; // should not reach here for valid inputs
}
